.app {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  justify-content: center;
  border-radius: var(--appsmith-theme-borderRadius);
  box-shadow: var(--appsmith-theme-boxShadow);
  padding: 29px 25px;
  box-sizing: border-box;
  font-family: system-ui;
}

/* AG Grid-specific customizations */
.ag-theme-alpine .ag-header {
  background: #fff !important;
  color: #222 !important;
}

.ag-theme-alpine .ag-row-selected {
  background: var(--appsmith-theme-primaryColor) !important;
  color: #fff !important;
}

.ag-theme-alpine {
  border-radius: var(--appsmith-theme-borderRadius);
  transition: box-shadow 0.2s;
  box-shadow: var(--appsmith-theme-boxShadow);
}

/* Modern button overrides if you want export, etc */
.ag-theme-alpine button {
  border-radius: 4px;
  border: 1px solid var(--appsmith-theme-primaryColor);
  background: var(--appsmith-theme-primaryColor);
  color: #fff;
  padding: 6px 16px;
  font-weight: 600;
  cursor: pointer;
}

