// Auto-generate column definitions
function generateColumns(data) {
  if (!Array.isArray(data) || data.length === 0) return [];
  return Object.keys(data[0]).map(key => ({
    headerName: key.charAt(0).toUpperCase() + key.slice(1),
    field: key,
    sortable: true,
    filter: true,
    resizable: true
  }));
}

// Safely extract data
function normalizeData(model) {
  return Array.isArray(model?.rows) && model.rows.length > 0 ? model.rows : [];
}

// Render grid
function renderGrid(model) {
  const rowData = normalizeData(model);
  const columnDefs = generateColumns(rowData);
  const gridOptions = {
    columnDefs,
    rowData,
    defaultColDef: {
      sortable: true,
      filter: true,
      resizable: true
    },
    domLayout: "autoHeight",
    animateRows: true,
    onRowClicked: params => {
      if (appsmith.triggerEvent) {
        appsmith.triggerEvent("onRowClick", params.data);
      }
    }
  };
  const gridDiv = document.getElementById("aggrid-root");
  if (!gridDiv) {
    console.error("Grid container not found!");
    return;
  }
  gridDiv.innerHTML = ""; // clear old grid
  new agGrid.Grid(gridDiv, gridOptions); // Use UMD global
}

// Initialize
appsmith.onReady(() => {
  console.log("Appsmith widget ready — rendering AG Grid");
  renderGrid(appsmith.model);
  appsmith.onModelChange(model => {
    console.log("Model changed:", model);
    renderGrid(model);
  });
});

